export enum AppView {
  DASHBOARD = 'DASHBOARD',
  STRATEGY_UPLOAD = 'STRATEGY_UPLOAD',
  BLUEPRINT_VIEW = 'BLUEPRINT_VIEW',
  CHAT = 'CHAT',
  LIVE_VOICE = 'LIVE_VOICE'
}

export interface AnalysisMetadata {
  analysisName: string;
  strategyVersion: string;
  applicableIndustries: string[];
  applicableRegions: string[];
  requiredBusinessInputs: string[];
  requiredExternalDataTypes: string[];
  analysisComplexityLevel: 'Standard' | 'High' | 'Advanced' | 'Enterprise';
  estimatedAnalysisDepth: string;
  dependencies: string[];
  constraints: string[];
}

export interface BlueprintStep {
  stepId: string;
  stepName: string;
  purpose: string;
  requiredInputs: string[];
  dataSources: string[];
  processingLogic: string;
  expectedIntermediateOutput: string;
  validationRules: string[];
  conditionsToProceed: string;
}

export interface AnalysisBlueprint {
  metadata: AnalysisMetadata;
  steps: BlueprintStep[];
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { AnalysisBlueprint } from "../types";

const API_KEY = process.env.API_KEY || "";

export const generateBlueprint = async (strategyText: string): Promise<AnalysisBlueprint> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `EXTRACT AND TRANSFORM THE FOLLOWING PROPRIETARY STRATEGY DOCUMENT INTO A STRUCTURED ANALYSIS BLUEPRINT.

    CORE RULES:
    - DO NOT analyze any specific business.
    - DO NOT generate conclusions or recommendations.
    - DEFINE ONLY THE LOGIC AND STRUCTURE.
    - Follow the user's terminology exactly.

    STRATEGY DOCUMENT:
    ${strategyText}
    `,
    config: {
      responseMimeType: "application/json",
      tools: [{ googleSearch: {} }],
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          metadata: {
            type: Type.OBJECT,
            properties: {
              analysisName: { type: Type.STRING },
              strategyVersion: { type: Type.STRING },
              applicableIndustries: { type: Type.ARRAY, items: { type: Type.STRING } },
              applicableRegions: { type: Type.ARRAY, items: { type: Type.STRING } },
              requiredBusinessInputs: { type: Type.ARRAY, items: { type: Type.STRING } },
              requiredExternalDataTypes: { type: Type.ARRAY, items: { type: Type.STRING } },
              analysisComplexityLevel: { type: Type.STRING },
              estimatedAnalysisDepth: { type: Type.STRING },
              dependencies: { type: Type.ARRAY, items: { type: Type.STRING } },
              constraints: { type: Type.ARRAY, items: { type: Type.STRING } },
            },
            required: ["analysisName", "strategyVersion", "applicableIndustries", "requiredBusinessInputs"]
          },
          steps: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                stepId: { type: Type.STRING },
                stepName: { type: Type.STRING },
                purpose: { type: Type.STRING },
                requiredInputs: { type: Type.ARRAY, items: { type: Type.STRING } },
                dataSources: { type: Type.ARRAY, items: { type: Type.STRING } },
                processingLogic: { type: Type.STRING },
                expectedIntermediateOutput: { type: Type.STRING },
                validationRules: { type: Type.ARRAY, items: { type: Type.STRING } },
                conditionsToProceed: { type: Type.STRING },
              },
              required: ["stepId", "stepName", "processingLogic"]
            }
          }
        },
        required: ["metadata", "steps"]
      }
    }
  });

  try {
    return JSON.parse(response.text || "{}") as AnalysisBlueprint;
  } catch (error) {
    console.error("Failed to parse blueprint JSON", error);
    throw new Error("Invalid blueprint format returned from API.");
  }
};

export const createChatSession = (systemInstruction: string) => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });
  return ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction,
    },
  });
};

