import React, { useState } from 'react';
import { generateBlueprint } from '../services/gemini';
import { AnalysisBlueprint } from '../types';

interface StrategyUploadProps {
  onBlueprintGenerated: (blueprint: AnalysisBlueprint) => void;
}

const StrategyUpload: React.FC<StrategyUploadProps> = ({ onBlueprintGenerated }) => {
  const [strategyText, setStrategyText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleProcess = async () => {
    if (!strategyText.trim()) return;
    setIsLoading(true);
    setError(null);
    try {
      const blueprint = await generateBlueprint(strategyText);
      onBlueprintGenerated(blueprint);
    } catch (err: any) {
      setError(err.message || 'An error occurred during blueprint generation.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      setStrategyText(text);
    };
    reader.readAsText(file);
  };

  return (
    <div className="max-w-4xl mx-auto py-12 px-6">
      <div className="bg-slate-800 border border-slate-700 rounded-xl overflow-hidden shadow-2xl">
        <div className="p-8 border-b border-slate-700 bg-slate-800/50">
          <h2 className="text-2xl font-bold text-white mb-2">Initialize Strategic Framework</h2>
          <p className="text-slate-400 text-sm">
            Input your proprietary strategy documentation. The engine will extract the logic, 
            inputs, and execution steps required to build a reusable analysis blueprint.
          </p>
        </div>

        <div className="p-8 space-y-6">
          <div className="flex items-center justify-between gap-4">
             <label className="flex-1 cursor-pointer group">
                <div className="border-2 border-dashed border-slate-700 group-hover:border-blue-500 rounded-lg p-6 text-center transition-colors">
                  <span className="text-slate-400 group-hover:text-blue-400 text-sm">
                    Click to upload strategy document (.txt, .md)
                  </span>
                  <input type="file" className="hidden" accept=".txt,.md" onChange={handleFileUpload} />
                </div>
             </label>
             <div className="text-slate-500 italic">or</div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-400 mb-2">Paste Strategy Text Directly</label>
            <textarea
              className="w-full h-64 bg-slate-900 border border-slate-700 rounded-lg p-4 text-slate-200 mono text-sm focus:ring-2 focus:ring-blue-500 focus:outline-none transition-all"
              placeholder="E.g. Step 1: Market Saturation Scoring. Inputs: Competitor count, Population density..."
              value={strategyText}
              onChange={(e) => setStrategyText(e.target.value)}
            />
          </div>

          {error && (
            <div className="p-4 bg-red-900/30 border border-red-500/50 text-red-400 rounded-lg text-sm">
              {error}
            </div>
          )}

          <button
            onClick={handleProcess}
            disabled={isLoading || !strategyText.trim()}
            className={`w-full py-4 rounded-lg font-bold text-lg transition-all flex items-center justify-center gap-3 ${
              isLoading || !strategyText.trim()
                ? 'bg-slate-700 text-slate-500 cursor-not-allowed'
                : 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-600/20'
            }`}
          >
            {isLoading ? (
              <>
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                Compiling Blueprint...
              </>
            ) : (
              'Generate Analysis Blueprint'
            )}
          </button>
        </div>
      </div>

      <div className="mt-8 grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { title: 'Zero Analysis', desc: 'The engine never looks at actual businesses. Privacy by design.' },
          { title: 'Strategy Pure', desc: 'No external frameworks added unless you define them.' },
          { title: 'Machine Ready', desc: 'Outputs are compatible with automated report generators.' }
        ].map((feat, i) => (
          <div key={i} className="p-4 bg-slate-800/30 rounded-lg border border-slate-700/50">
            <h4 className="text-sm font-semibold text-slate-300 mb-1">{feat.title}</h4>
            <p className="text-xs text-slate-500">{feat.desc}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

