import React, { useState, useEffect, useRef } from 'react';
import { createChatSession } from '../services/gemini';
import { ChatMessage, AnalysisBlueprint } from '../types';

interface ChatProps {
  blueprint: AnalysisBlueprint | null;
}

const Chat: React.FC<ChatProps> = ({ blueprint }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const chatRef = useRef<any>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const instruction = `You are an expert Strategic Framework Designer. 
    ${blueprint ? `Current Blueprint Loaded: ${JSON.stringify(blueprint.metadata)}` : "No blueprint loaded yet."}
    Help the user refine their strategy, explain complex logic, or plan data sourcing for their business analysis blueprint.
    DO NOT ANALYZE ACTUAL BUSINESSES. Stay focused on STRATEGY ARCHITECTURE.`;

    chatRef.current = createChatSession(instruction);
  }, [blueprint]);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || !chatRef.current) return;

    const userMsg: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const response = await chatRef.current.sendMessage({ message: input });
      const modelMsg: ChatMessage = { role: 'model', text: response.text || 'Error generating response' };
      setMessages(prev => [...prev, modelMsg]);
    } catch (err) {
      console.error(err);
      setMessages(prev => [...prev, { role: 'model', text: 'Error interacting with AI engine.' }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="h-[calc(100vh-2rem)] max-w-4xl mx-auto flex flex-col p-4">
      <div className="flex-1 bg-slate-800 border border-slate-700 rounded-t-xl overflow-y-auto p-6 space-y-6">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center p-8">
            <div className="w-16 h-16 bg-blue-600/20 rounded-full flex items-center justify-center text-3xl mb-4">💬</div>
            <h3 className="text-xl font-bold text-white mb-2">Strategy Architect AI</h3>
            <p className="text-slate-400 max-w-sm">
              Ask questions about your framework, refine processing logic, or discuss data dependencies.
            </p>
          </div>
        )}

        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[80%] p-4 rounded-xl text-sm ${
              msg.role === 'user' 
                ? 'bg-blue-600 text-white shadow-lg' 
                : 'bg-slate-900 text-slate-200 border border-slate-700'
            }`}>
              <p className="whitespace-pre-wrap">{msg.text}</p>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-slate-900 p-4 rounded-xl flex gap-1 items-center border border-slate-700">
              <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:0.2s]"></div>
              <div className="w-1.5 h-1.5 bg-slate-500 rounded-full animate-bounce [animation-delay:0.4s]"></div>
            </div>
          </div>
        )}
        <div ref={scrollRef} />
      </div>

      <div className="bg-slate-900 border-x border-b border-slate-700 p-4 rounded-b-xl">
        <div className="flex gap-2">
          <input
            type="text"
            className="flex-1 bg-slate-800 border border-slate-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
            placeholder="Discuss strategy architecture..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isTyping}
            className="bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 text-white px-6 py-3 rounded-lg font-bold transition-all shadow-lg shadow-blue-600/20"
          >
            Send
          </button>
        </div>
      </div>
    </div>
  );
};

export default Chat;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GoogleGenAI, Modality } from '@google/genai';

const LiveVoice: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState('Disconnected');
  const [transcription, setTranscription] = useState('');

  const audioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef(new Set<AudioBufferSourceNode>());

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const decodeAudioData = async (data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number) => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const encode = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const startSession = async () => {
    const API_KEY = process.env.API_KEY || "";
    const ai = new GoogleGenAI({ apiKey: API_KEY });

    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStatus('Active');
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(session => session.sendRealtimeInput({ media: pcmBlob }));
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message) => {
            if (message.serverContent?.outputTranscription) {
               setTranscription(prev => prev + ' ' + message.serverContent.outputTranscription.text);
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              const ctx = audioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => {
            console.error('Live API Error', e);
            setStatus('Error');
          },
          onclose: () => {
            setStatus('Closed');
            setIsActive(false);
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          outputAudioTranscription: {},
          systemInstruction: 'You are the Strategic Voice Assistant for the Analysis Blueprint Engine. Help the user design better strategic frameworks using human-like audio conversation. Keep discussions abstract and focused on data logic, not specific business evaluation.'
        }
      });

      sessionRef.current = await sessionPromise;
      setIsActive(true);
    } catch (err) {
      console.error(err);
      setStatus('Access Denied');
    }
  };

  const stopSession = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    setIsActive(false);
    setStatus('Disconnected');
  };

  return (
    <div className="max-w-xl mx-auto py-24 px-6 text-center">
      <div className={`w-32 h-32 rounded-full mx-auto mb-8 flex items-center justify-center transition-all duration-700 ${isActive ? 'bg-blue-600 scale-110 shadow-[0_0_50px_rgba(37,99,235,0.5)] animate-pulse' : 'bg-slate-800'}`}>
        <span className="text-5xl">{isActive ? '🎙️' : '🔇'}</span>
      </div>

      <h2 className="text-3xl font-bold text-white mb-2">Voice Strategy Studio</h2>
      <p className="text-slate-400 mb-8">
        Enter real-time conversation mode with the Gemini 2.5 Native Audio engine to discuss framework architectural decisions.
      </p>

      <div className="bg-slate-800/50 border border-slate-700 rounded-xl p-6 mb-8 text-left">
        <div className="flex items-center gap-2 mb-4">
          <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-green-500 animate-ping' : 'bg-slate-600'}`}></div>
          <span className="text-xs font-semibold text-slate-500 uppercase tracking-widest">Status: {status}</span>
        </div>
        <div className="min-h-[100px] text-sm text-slate-300 italic mono leading-relaxed">
          {isActive ? (transcription || 'Listening for strategy input...') : 'Voice engine offline. Initialize session to begin.'}
        </div>
      </div>

      <button
        onClick={isActive ? stopSession : startSession}
        className={`w-full py-4 rounded-xl font-bold text-lg transition-all shadow-xl ${isActive ? 'bg-red-600 hover:bg-red-500 shadow-red-900/20' : 'bg-blue-600 hover:bg-blue-500 shadow-blue-900/20'}`}
      >
        {isActive ? 'Terminate Session' : 'Initialize Voice Link'}
      </button>

      <p className="mt-6 text-xs text-slate-500">
        Requires Microphone Access. Audio is processed in real-time for strategy architecture purposes.
      </p>
    </div>
  );
};

